// Local-first cache (IndexedDB via Dexie).
//
// This is the client storage tier from the Email 2.0 proposal §8: the UI paints
// from here before the network responds, and network results are written back
// so the next warm load is instant. Records are scoped by `account` (the signed
// in email) so switching accounts never bleeds one mailbox into another.
//
// We intentionally cache only what the list and read views need:
//   - threads:      the envelope-derived rows that render the mailbox list
//   - messageBodies: full message bodies, fetched lazily when a thread is opened
//
// Nothing here is a source of truth — IMAP is. The cache is disposable and can
// be cleared at any time without data loss.

import Dexie, { type Table } from "dexie";
import type { Thread, ThreadMessage } from "../core/DataContext";

// A cached mailbox-list row. `account` and `role` let us query a single folder
// for a single user; `key` is the primary key (account + thread id) so the same
// UID in two accounts never collides.
export interface CachedThread extends Thread {
  key: string;
  account: string;
  role: string; // "inbox" | "sent" | "drafts" | "trash"
  cachedAt: number;
}

// A cached message body, keyed by account + thread id.
export interface CachedBody {
  key: string;
  account: string;
  threadId: string;
  message: ThreadMessage;
  cachedAt: number;
}

// Per-folder sync state (proposal §8 "mailboxes" row). `uidvalidity` is the IMAP
// cache-coherence guard: if the server reports a different value, the cached
// UIDs are stale and the folder must be refetched from scratch. Persisting this
// lets a warm start refresh via a delta instead of a full re-list.
export interface SyncMeta {
  key: string; // account + role
  account: string;
  role: string;
  uidvalidity: number;
  updatedAt: number;
}

class QuicksilverCache extends Dexie {
  threads!: Table<CachedThread, string>;
  bodies!: Table<CachedBody, string>;
  syncMeta!: Table<SyncMeta, string>;

  constructor() {
    super("quicksilver-cache");
    this.version(1).stores({
      // Compound-ish secondary index [account+role] powers per-folder reads.
      threads: "key, account, role, [account+role]",
      bodies: "key, account, threadId",
    });
    // v2 adds per-folder sync state for delta sync. Dexie carries existing
    // threads/bodies data forward unchanged across the version bump.
    this.version(2).stores({
      syncMeta: "key, account",
    });
  }
}

export const db = new QuicksilverCache();

function threadKey(account: string, threadId: string): string {
  return `${account}�${threadId}`;
}

// ---- Threads (mailbox-list rows) -------------------------------------------

// Read every cached thread for one folder of one account, newest first.
export async function readThreads(
  account: string,
  role: string,
): Promise<Thread[]> {
  if (!account) return [];
  try {
    const rows = await db.threads
      .where("[account+role]")
      .equals([account, role])
      .toArray();
    rows.sort(
      (a, b) =>
        new Date(b.lastMessageTime).getTime() -
        new Date(a.lastMessageTime).getTime(),
    );
    return rows.map(stripCacheFields);
  } catch {
    // A cache read must never break the app — fall back to an empty cache.
    return [];
  }
}

// Replace the cached contents of one folder with a fresh network result. We
// delete-then-bulk-put inside a transaction so a folder that lost messages
// upstream (moved/deleted elsewhere) doesn't keep stale rows around.
export async function writeThreads(
  account: string,
  role: string,
  threads: Thread[],
): Promise<void> {
  if (!account) return;
  try {
    const now = Date.now();
    const rows: CachedThread[] = threads.map((t) => ({
      ...t,
      key: threadKey(account, t.id),
      account,
      role,
      cachedAt: now,
    }));
    await db.transaction("rw", db.threads, async () => {
      await db.threads.where("[account+role]").equals([account, role]).delete();
      if (rows.length) await db.threads.bulkPut(rows);
    });
  } catch {
    // Best-effort persistence; a write failure just means a colder next load.
  }
}

// Remove a single thread from the cache (used by optimistic delete).
export async function removeThread(
  account: string,
  threadId: string,
): Promise<void> {
  if (!account) return;
  try {
    await db.threads.delete(threadKey(account, threadId));
  } catch {
    /* ignore */
  }
}

// Patch a single cached thread in place (used by optimistic mark-as-read).
export async function patchThread(
  account: string,
  threadId: string,
  patch: Partial<Thread>,
): Promise<void> {
  if (!account) return;
  try {
    await db.threads.update(threadKey(account, threadId), patch);
  } catch {
    /* ignore */
  }
}

// ---- Message bodies --------------------------------------------------------

export async function readBody(
  account: string,
  threadId: string,
): Promise<ThreadMessage | null> {
  if (!account) return null;
  try {
    const row = await db.bodies.get(threadKey(account, threadId));
    return row ? row.message : null;
  } catch {
    return null;
  }
}

export async function writeBody(
  account: string,
  threadId: string,
  message: ThreadMessage,
): Promise<void> {
  if (!account) return;
  try {
    await db.bodies.put({
      key: threadKey(account, threadId),
      account,
      threadId,
      message,
      cachedAt: Date.now(),
    });
  } catch {
    /* ignore */
  }
}

// ---- Sync state ------------------------------------------------------------

// Read the cached UIDVALIDITY for one folder (0 if none stored yet).
export async function readUidValidity(
  account: string,
  role: string,
): Promise<number> {
  if (!account) return 0;
  try {
    const row = await db.syncMeta.get(threadKey(account, role));
    return row?.uidvalidity ?? 0;
  } catch {
    return 0;
  }
}

// Persist the UIDVALIDITY observed for one folder.
export async function writeUidValidity(
  account: string,
  role: string,
  uidvalidity: number,
): Promise<void> {
  if (!account || !uidvalidity) return;
  try {
    await db.syncMeta.put({
      key: threadKey(account, role),
      account,
      role,
      uidvalidity,
      updatedAt: Date.now(),
    });
  } catch {
    /* ignore */
  }
}

// Drop everything for one account (e.g. on logout). Leaves other accounts'
// caches intact for fast re-login.
export async function clearAccount(account: string): Promise<void> {
  if (!account) return;
  try {
    await db.transaction("rw", db.threads, db.bodies, db.syncMeta, async () => {
      await db.threads.where("account").equals(account).delete();
      await db.bodies.where("account").equals(account).delete();
      await db.syncMeta.where("account").equals(account).delete();
    });
  } catch {
    /* ignore */
  }
}

function stripCacheFields(row: CachedThread): Thread {
  const { key: _k, account: _a, role: _r, cachedAt: _c, ...thread } = row;
  return thread;
}
